examples.original_ir:
define i32 @test(i1 %cond, i32 %a, i32 %b, i32 %c) {
  %div1 = sdiv i32 %a, %b
  %div2 = sdiv i32 %a, %c
  %res = select i1 %cond, i32 %div1, i32 %div2
  ret i32 %res
}

examples.optimized_ir:
define i32 @test(i1 %cond, i32 %a, i32 %b, i32 %c) {
  %sel = select i1 %cond, i32 %b, i32 %c
  %res = sdiv i32 %a, %sel
  ret i32 %res
}
